        T.warstwa = L->warstwa;
        T.kolor = L->kolor;
        T.czcionka = zmwym.czcionka;
        T.wysokosc = (float)(zmwym.wysokosc * 0.5);
        if (Check_if_Equal2(dx, PL1.dl))
            T.kat = (float)(Pi_ * (PL.kat+180) / 180);
