static short get_invert(int el_no ) {
    AVECTOR v=Vdef;
    int ret;

    v.x1 = (float)st_node[st_element[el_no].node1].x ;
    v.y1 = (float)st_node[st_element[el_no].node1].y ;
    v.x2 = (float)st_node[st_element[el_no].node2].x ;
    v.y2 = (float)st_node[st_element[el_no].node2].y ;
    ret = get_thermal_flipped(&v);
    if (ret==0) return 1;
    else return -1;
}


/*
 * @brief Calculates drawing coordinates for a displaced point in a standard
 *        120-degree (Farish) isometric projection.
 *
 * @param Le        Line structure containing drawing coordinates (x1, y1, x2, y2)
 * @param len_cart  Real 3D length of the member (Cartesian)
 * @param x_cart    Distance along member from start node (Cartesian)
 * @param dx_loc    Local displacement: along member axis
 * @param dy_loc    Local displacement: transverse in XY plane
 * @param dz_loc    Local displacement: vertical (Z)
 */
int getDisplacedIsoPoint(LINIA *Le, double len_cart, double x_cart,
                         double dx_loc, double dy_loc, double dz_loc,
                         double *px, double *py, double *pdx, double *pdy) {

    if (len_cart <= 0) return 0;

    ////if (x_cart>len_cart) x_cart=len_cart;   //I can't do that

    // Standard Isometric Constants (30 degrees)
    const double COS30 = 0.86602540378; // sqrt(3)/2
    const double SIN30 = 0.5;

    // 1. Calculate the base point (px, py) on the drawing
    double ratio = x_cart / len_cart;
    *px = Le->x1 + ratio * (Le->x2 - Le->x1);
    *py = Le->y1 + ratio * (Le->y2 - Le->y1);

    // 2. Derive Global Cartesian Direction Cosines (cx, cy)
    // In Farish Iso:
    // dx_iso = (X_cart - Y_cart) * COS30
    // dy_iso = (X_cart + Y_cart) * SIN30
    double dX_draw = Le->x2 - Le->x1;
    double dY_draw = Le->y2 - Le->y1;

    // Solve for Cartesian deltas:
    double dX_cart = (dX_draw / (2.0 * COS30)) + (dY_draw / (2.0 * SIN30));
    double dY_cart = (dY_draw / (2.0 * SIN30)) - (dX_draw / (2.0 * COS30));

    double cx = dX_cart / len_cart;
    double cy = dY_cart / len_cart;

    // 3. Local to Global Rotation (XY Plane)
    // Rotate the local Frame3DD results into Global Cartesian space
    double DX_glob = dx_loc * cx - dy_loc * cy;
    double DY_glob = dx_loc * cy + dy_loc * cx;
    double DZ_glob = dz_loc; // Z is vertical

    // 4. Global Cartesian to Isometric Drawing Projection
    // This maps the 3D displacements back to the 2D drawing offsets
    double draw_offset_x = (DX_glob - DY_glob) * COS30;
    double draw_offset_y = (DX_glob + DY_glob) * SIN30 + DZ_glob;

    // 5. Final Coordinates
    *pdx = *px + draw_offset_x;
    *pdy = *py + draw_offset_y;

    return 1;
}

