void drawRibbonSegment(LINIA *Le, double len_cart, double x_start, double x_end,
                       double val_start, double val_end, double max_val,
                       double ribbon_width_iso) {

    // 1. Calculate base points (px, py) on drawing for both ends of segment
    // Using the previously refined isometric logic
    double px1, py1, pdx1, pdy1, px2, py2, pdx2, pdy2;
    //double dummy_total;

    // We assume getDisplacedIsoPoint finds the base point (px, py)
    // For the ribbon, we use the base point without linear displacement offsets
    getDisplacedIsoPoint(Le, len_cart, x_start, 0, 0, 0, &px1, &py1, &pdx1, &pdy1); //, &dummy_total);
    getDisplacedIsoPoint(Le, len_cart, x_end, 0, 0, 0, &px2, &py2, &pdx2, &pdy2); //, &dummy_total);

    // 2. Determine the "perpendicular" direction on the drawing for the ribbon width
    // Since Z is vertical, the most stable "width" for the ribbon is vertical.
    double dx_draw = px2 - px1;
    double dy_draw = py2 - py1;
    double len_draw = sqrt(dx_draw * dx_draw + dy_draw * dy_draw);

    // Unit vector perpendicular to the member on the drawing
    double nx = -dy_draw / len_draw;
    double ny = dx_draw / len_draw;

    // 3. Define the 4 Corners of the Quadrangular "Solid"
    // Each end of the segment gets two points offset by the ribbon width
    double half_w = ribbon_width_iso / 2.0;

    double x_corners[4], y_corners[4];
    unsigned int colors[4];

    // Start of segment (Side 1 and 2)
    x_corners[0] = px1 + nx * half_w; y_corners[0] = py1 + ny * half_w;
    x_corners[1] = px1 - nx * half_w; y_corners[1] = py1 - ny * half_w;

    // End of segment (Side 3 and 4)
    x_corners[2] = px2 - nx * half_w; y_corners[2] = py2 - ny * half_w;
    x_corners[3] = px2 + nx * half_w; y_corners[3] = py2 + ny * half_w;

    // 4. Assign Colors based on intensity at each end
    unsigned int color_start = getRGB(val_start, max_val);
    unsigned int color_end   = getRGB(val_end, max_val);

    colors[0] = color_start;
    colors[1] = color_start;
    colors[2] = color_end;
    colors[3] = color_end;

    // 5. Call your Solid drawing engine
    // drawSolid4PointGradient(x_corners, y_corners, colors);
}


double calculate_Jx(double h, double b) {
    double a = (h > b) ? h : b; // a is always the longer side
    double s = (h > b) ? b : h; // s is the shorter side (b in your formula)

    double s2 = s * s;
    double s3 = s2 * s;
    double s4 = s2 * s2;
    double s8 = s4 * s4;
    double a4 = (a * a) * (a * a);

    // It = (a*s^3)/3 - 0.21*s^4 + 0.0175*(s^8/a^4)
    double It = (a * s3 / 3.0) - (0.21 * s4) + (0.0175 * s8 / a4);

    return It;
}

