void upgrade_D(COMBI_FORCES *fd, DATA_ROW *dr, int inx, int inxi, int revert, int element_no)
{
        fd[inx].Dx_min = min(fd[inx].Dx_min, dr[inx].Dx);
        fd[inx].Dx_max = max(fd[inx].Dx_max, dr[inx].Dx);

        fd[inx].Dy_min = min(fd[inx].Dy_min, dr[inx].Dy);
        fd[inx].Dy_max = max(fd[inx].Dy_max, dr[inx].Dy);

        fd[inx].Dz_min = min(fd[inx].Dz_min, dr[inx].Dz);
        fd[inx].Dz_max = max(fd[inx].Dz_max, dr[inx].Dz);

        fd[inx].Rx_min = min(fd[inx].Rx_min, dr[inx].Rx);
        fd[inx].Rx_max = max(fd[inx].Rx_max, dr[inx].Rx);
}

BOOL check_if_first(int element_no)
{
    if ((st_element[element_no - 1].flags==0)  ||  //normal, not Winkler
    ((st_element[element_no - 1].flags==1) &&  //winkler
    ((element_no - 1==0) || (st_element[element_no - 2].flags==0) ||  //and it's first element at all, or previous element is not Winkler
    ((st_element[element_no - 1].peer) != (st_element[element_no - 2].peer)))))  //or previous Winkler is different peer
        return TRUE;
    else return FALSE;
}

static BOOL  CheckIfNodeForce(AVECTOR *v)
{
    for (int i=0; i<st_node_force_moment_no; i++)
    {
        if ((Check_if_Equal(st_node[st_node_force_moment[i].node].x, v->x1) && Check_if_Equal(st_node[st_node_force_moment[i].node].y, v->y1)) &&
            (st_node_force_moment[i].style ==v->style))
        {
            return TRUE;
        }
    }
    return FALSE;
}

