void DiscoverGlobalPeaks(const char* peaksFilePath, int ret_standard, UNIT_FACTORS *unit_factors_, double fyd_min) {
    FILE* file = fopen(peaksFilePath, "r");
    if (!file) return;

    /*
fprintf(fp_peaks, "%e %e %e %e %e %e %e %e %e\n",
                 g_auto_max_Nx, g_auto_max_Vy, g_auto_max_Vz, g_auto_max_Tx,
                 g_auto_max_Myy, g_auto_max_Mzz,
                 g_auto_max_Dxyz, g_auto_max_Dy, g_auto_max_Dz);
     */
    
    double EPSILON = 0.0001;

    double max_Nx, max_Vy, max_Vz, max_Tx, max_Myy, max_Mzz, max_Dxyz, max_Dy, max_Dz, max_Rx, max_Ry, max_Rz, max_RMxx, max_RMyy, max_RMzz,
           max_Qx, max_Qy, max_Qz, max_QMxx, max_QMyy, max_QMzz, max_sigma, max_tau;
 /*
  g_auto_max_Nx, g_auto_max_Vy, g_auto_max_Vz, g_auto_max_Tx,
                 g_auto_max_Myy, g_auto_max_Mzz,
                 g_auto_max_Dxyz, g_auto_max_Dy, g_auto_max_Dz, g_auto_max_Rx, g_auto_max_Ry, g_auto_max_Rz, g_auto_max_RMxx, g_auto_max_RMyy, g_auto_max_RMzz, g_auto_max_sigma, g_auto_max_tau
  */
    // Read the entire global envelope state in a single operation
    if (fscanf(file, "%lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf %lf", &max_Nx, &max_Vy, &max_Vz, &max_Tx, &max_Myy, &max_Mzz, &max_Dxyz, &max_Dy, &max_Dz, &max_Rx, &max_Ry, &max_Rz, &max_RMxx, &max_RMyy, &max_RMzz,
               &max_Qx, &max_Qy, &max_Qz, &max_QMxx, &max_QMyy, &max_QMzz, &max_sigma, &max_tau) == 23) {
        // Instantly calculate the perfect visual paper footprints
        double cfg_ref_n;
        double cfg_ref_v;
        double cfg_ref_m;
        double cfg_ref_d;
        double cfg_ref_r;
        double cfg_ref_rm;
        double cfg_ref_s;
        double cfg_ref_ss;
        double cfg_ref_src;
        double cfg_ref_p;
        double cfg_ref_shear;

        if (UNITS==SI) //kN, kNm, mm, Mpa, kN/m
        {
            cfg_ref_n = cfg_ref_n_base;  //kN
            cfg_ref_v = cfg_ref_v_base;  //kN
            cfg_ref_m = cfg_ref_m_base;  //kNm
            cfg_ref_d = cfg_ref_d_base;  //mm
            cfg_ref_r = cfg_ref_r_base;  //kN
            cfg_ref_rm = cfg_ref_rm_base; //kNm
            cfg_ref_s = cfg_ref_s_base; //Mpa
            cfg_ref_ss = cfg_ref_ss_base; //Mpa
            cfg_ref_src = cfg_ref_src_base; //Mpa
            cfg_ref_p = cfg_ref_p_base; // %
            cfg_ref_shear = cfg_ref_shear_base; //kN/m
        }
        else //kips, kip-in, in, ksi, kip/in
        {
            // 50 kN -> ~11.24 kips
            cfg_ref_n = cfg_ref_n_base * 0.22480894;
            // 50 kN -> ~11.24 kips
            cfg_ref_v = cfg_ref_v_base * 0.22480894;
            // 10 kNm -> ~88.51 kip-in (10 * 8.850745)
            cfg_ref_m = cfg_ref_m_base * 8.85074579;
            // 20 mm -> ~0.787 in
            cfg_ref_d = cfg_ref_d_base * 0.03937008;
            // 50 kN -> ~11.24 kips
            cfg_ref_r = cfg_ref_r_base * 0.22480894;
            // 50 kNm -> ~442.54 kip-in (50 * 8.850745)
            cfg_ref_rm = cfg_ref_rm_base * 8.85074579;
            // 50 MPa -> ~7.25 ksi
            cfg_ref_s = cfg_ref_s_base * 0.14503774;
            // 5 MPa -> ~0.725 ksi
            cfg_ref_ss = cfg_ref_ss_base * 0.14503774;
            // 15 MPa -> ~2.18 ksi
            cfg_ref_src = cfg_ref_src_base * 0.14503774;
            // Reinforcement ratio percentage is universally a ratio (2.0% is 2.0%)
            cfg_ref_p = cfg_ref_p_base;
            // 30 kN/m -> ~0.171 kips/in (30 * 0.22480894 / 39.370078)
            cfg_ref_shear = cfg_ref_shear_base * 0.00571015;
        }

        max_Nx /= unit_factors_->F_f;
        max_Vy /= unit_factors_->F_f;
        max_Vz /= unit_factors_->F_f;
        max_Myy /= unit_factors_->M_f;
        max_Mzz /= unit_factors_->M_f;
        max_Rx /= unit_factors_->R_f;
        max_Ry /= unit_factors_->R_f;
        max_Rz /= unit_factors_->R_f;
        max_RMxx /= unit_factors_->M_f;
        max_RMyy /= unit_factors_->M_f;
        max_RMzz /= unit_factors_->M_f;
        max_Qz /= unit_factors_->q_f;

        double gov_max_Nx    = (max_Nx > cfg_ref_n)    ? max_Nx    : cfg_ref_n;
        double gov_max_Vy    = (max_Vy > cfg_ref_v)    ? max_Vy    : cfg_ref_v;
        double gov_max_Vz    = (max_Vz > cfg_ref_v)    ? max_Vz    : cfg_ref_v;
        double gov_max_Myy    = (max_Myy > cfg_ref_m)    ? max_Myy    : cfg_ref_m;
        double gov_max_Mzz    = (max_Mzz > cfg_ref_m)    ? max_Mzz    : cfg_ref_m;
        double gov_max_Dxyz    = (max_Dxyz > cfg_ref_d)    ? max_Dxyz    : cfg_ref_d;
        double gov_max_Dy    = (max_Dy > cfg_ref_d)    ? max_Dy    : cfg_ref_d;
        double gov_max_Dz    = (max_Dz > cfg_ref_d)    ? max_Dz    : cfg_ref_d;
        double gov_max_Rx    = (max_Rx > cfg_ref_r)    ? max_Rx    : cfg_ref_r;
        double gov_max_Ry    = (max_Ry > cfg_ref_r)    ? max_Ry    : cfg_ref_r;
        double gov_max_Rz    = (max_Rz > cfg_ref_r)    ? max_Rz    : cfg_ref_r;
        double gov_max_RMxx    = (max_RMxx > cfg_ref_rm)    ? max_RMxx    : cfg_ref_rm;
        double gov_max_RMyy    = (max_RMyy > cfg_ref_rm)    ? max_RMyy    : cfg_ref_rm;
        double gov_max_RMzz    = (max_RMzz > cfg_ref_rm)    ? max_RMzz    : cfg_ref_rm;

        n_magnitude = (gov_max_Nx > EPSILON) ? ((gov_max_Nx) / n_desire_footprint) : 1.0;
        double v_magnitude_y = (gov_max_Vy > EPSILON) ? ((gov_max_Vy) / v_desire_footprint) : 1.0;
        double v_magnitude_z = (gov_max_Vz > EPSILON) ? ((gov_max_Vz) / v_desire_footprint) : 1.0;
        v_magnitude=max(v_magnitude_y, v_magnitude_z);
        double m_magnitude_yy = (gov_max_Myy > EPSILON) ? ((gov_max_Myy) / m_desire_footprint) : 1.0;
        double m_magnitude_zz = (gov_max_Mzz > EPSILON) ? ((gov_max_Mzz) / m_desire_footprint) : 1.0;
        m_magnitude=max(m_magnitude_yy, m_magnitude_zz);
        double d_magnitude_xyz = (gov_max_Dxyz > EPSILON) ? (gov_max_Dxyz / d_desire_footprint) : 1.0;
        double d_magnitude_y = (gov_max_Dy > EPSILON) ? (gov_max_Dy / d_desire_footprint) : 1.0;
        double d_magnitude_z = (gov_max_Dz > EPSILON) ? (gov_max_Dz / d_desire_footprint) : 1.0;
        d_magnitude=max(max(d_magnitude_y, d_magnitude_z), d_magnitude_xyz);

        double r_magnitude_x = (gov_max_Rx > EPSILON) ? ((gov_max_Rx) / r_desire_footprint) : 1.0;
        double r_magnitude_y = (gov_max_Ry > EPSILON) ? ((gov_max_Ry) / r_desire_footprint) : 1.0;
        double r_magnitude_z = (gov_max_Rz > EPSILON) ? ((gov_max_Rz) / r_desire_footprint) : 1.0;
        r_magnitude=max(max(r_magnitude_x, r_magnitude_y), r_magnitude_z);

        double rm_magnitude_xx = (gov_max_RMxx > EPSILON) ? ((gov_max_RMxx) / rm_desire_footprint) : 1.0;
        double rm_magnitude_yy = (gov_max_RMyy > EPSILON) ? ((gov_max_RMyy) / rm_desire_footprint) : 1.0;
        double rm_magnitude_zz = (gov_max_RMzz > EPSILON) ? ((gov_max_RMzz) / rm_desire_footprint) : 1.0;
        rm_magnitude=max(max(rm_magnitude_xx, rm_magnitude_yy), rm_magnitude_zz);

        if (UNITS==IMP) {
            max_sigma /= 1000.0;    //from psi to ksi
            max_tau /= 1000.0;
            max_Qz /= 1000.0;
        }

        double gov_max_sigma = (max_sigma > cfg_ref_s)    ? max_sigma : cfg_ref_s;
        double gov_max_tau = (max_tau > cfg_ref_ss)    ? max_tau : cfg_ref_ss;
        double gov_max_Qz    = (max_Qz > cfg_ref_shear)   ? max_Qz    : cfg_ref_shear;

        shear_magnitude = (gov_max_Qz > EPSILON) ? ((gov_max_Qz) / shear_desire_footprint) : 1.0;
        s_magnitude = (gov_max_sigma > EPSILON) ? (gov_max_sigma / s_desire_footprint) : 1.0;

        ss_magnitude = (gov_max_tau > EPSILON) ? (gov_max_tau / ss_desire_footprint) : 1.0;

        double fyd_base;
        /*
        // Now assign your physics bridge baseline safely based on the true active minimum
        if (ret_standard == 1) { // EUROCODE
            fyd_base = (UNITS == SI) ? fyd_min : (fyd_min * 0.1450377);
        }
        else { // ASCE / ACI
            fyd_base = (UNITS == SI) ? (60.0 * 6.894757) : 60.0; // ACI framework standardizes on Gr 60
        }
         */
        // Now assign your physics bridge baseline safely based on the true active minimum
        if (ret_standard == 1) { // EUROCODE
            if (strcmp(UNITS, "SI") == 0) {
                fyd_base = fyd_min; // Natively in MPa (e.g., 350.0)
            } else {
                // --- FIX: Divide by 1000.0 instead of multiplying by 0.1450377 ---
                // Since fyd_min is already in psi (50763.2), this converts it cleanly to ksi (~50.76)
                fyd_base = fyd_min / 1000.0;
            }
        }
        else { // ASCE / ACI
            fyd_base = (strcmp(UNITS, "SI") == 0) ? (60.0 * 6.894757) : 60.0;
        }

        // Complete the bridge calculations cleanly
        double sigma_4 = 0.216 * fyd_base;
        double src_magnitude_4 = (sigma_4 / s_desire_footprint);

        src_magnitude = (src_magnitude_4 > s_magnitude) ? src_magnitude_4 : s_magnitude;

        sp_magnitude  = s_magnitude;
        sm_magnitude  = s_magnitude;

        // The governing physics equation remains perfectly universal and clean
        double estimated_rho = (max_sigma / (5.4 * fyd_base)) * 100.0;

        if (estimated_rho < 0.15) estimated_rho = 0.15; // Minimum bounding guard
        if (estimated_rho > 4.0)  estimated_rho = 4.0;  // Maximum bounding guard

        p_magnitude   = (estimated_rho / p_desire_footprint); // * p_est_factor;

        //alternative limitation for reinforcement ratio envelope, if estimated rho exceeds 4.%
        double p_magnitude_4 = (4.0 / p_desire_footprint);

        p_magnitude = (p_magnitude_4>p_magnitude) ? p_magnitude_4 : p_magnitude;

        g_auto_max_sigma=max_sigma;

    }
    fclose(file);
}


static int get_property_parameters(ST_ELEMENT *elem, ST_PROPERTY *property)
{   int j;

    for (j = 0; j < st_property_no; j++) {
        if (abs(elem->property_no) == st_property[j].n)
            break;
    }

    if (j == st_property_no) return 0;

    memmove(property, &st_property[j], sizeof(ST_PROPERTY));

    return 1;
}

#define STANDARD_EUROCODE 1
#define STANDARD_ASCE     2
#define STANDARD_ICC      3

double GetConcreteFcr(ST_PROPERTY* prop, int ret_standard)
{
    // 1. Isolate the Unit System cleanly
    int is_metric = (UNITS==SI)? 1 : 0;

    // Core parameters normalized to their native input state
    double input_fck = prop->fck;
    double input_fcd = prop->fcd;
    double input_fyk = prop->fyk;
    double input_fyd = prop->fyd;

    // ============================================================================
    // STEP 1: CALCULATE THE RAW STRUCTURAL COMPRESSIVE VALUE (fck / f'c)
    // ============================================================================
    double fck_normalized = 0.0;

    if (input_fck > 0.0) {
        fck_normalized = input_fck;
    } else if (input_fcd > 0.0) {
        // Material safe factor transition fallback
        fck_normalized = (ret_standard == STANDARD_EUROCODE) ? (input_fcd * 1.5) : input_fcd;
    } else {
        // Inferred fallback based on the mandatory steel grade
        double inferred_fy = (input_fyk > 0.0) ? input_fyk : (input_fyd * ((ret_standard == STANDARD_EUROCODE) ? 1.15 : 1.0));

        if (is_metric) {
            // Metric thresholds (in MPa)
            fck_normalized = (inferred_fy <= 420.0) ? 25.0 : 30.0;
        } else {
            // Imperial thresholds (in kpsi)
            fck_normalized = (inferred_fy <= 50.0) ? 3.0 : 4.0;
        }
    }

    // ============================================================================
    // STEP 2: EXECUTE CRACKING MATHEMATICS BASED ON CHOSEN CODE PHILSOPHY
    // ============================================================================

    if (ret_standard == STANDARD_EUROCODE) {
        // Eurocode formula inherently expects input in MPa
        double fck_in_mpa = is_metric ? fck_normalized : (fck_normalized * 6.89476); // kpsi to MPa

        double fcr_in_mpa = 0.30 * pow(fck_in_mpa, 2.0 / 3.0);

        // Return result converted back to active workspace unit
#ifndef NDEBUG
        printf("fcr=%f\n", is_metric ? fcr_in_mpa : (fcr_in_mpa / 6.89476));
#endif
        return is_metric ? fcr_in_mpa : (fcr_in_mpa / 6.89476);
    }
    else {
        // ACI 318 formula inherently expects input in pure psi (not kpsi, not MPa)
        double fc_prime_in_psi = is_metric ? (fck_normalized * 145.038) : (fck_normalized * 1000.0);

        double fcr_in_psi = 7.5 * sqrt(fc_prime_in_psi);

        // Return result converted back to active workspace unit
#ifndef NDEBUG
        printf("fcr=%f\n", is_metric ? (fcr_in_psi / 145.038) : (fcr_in_psi / 1000.0));
#endif
        return is_metric ? (fcr_in_psi / 145.038) : (fcr_in_psi / 1000.0);
    }
}

