                        Lr.y1 = (float) st_node[st_element[i].node1].y;
                        Lr.x2 = (float) st_node[st_element[i].node2].x;
                        Lr.y2 = (float) st_node[st_element[i].node2].y;

                        ldf = sqrtf((L.x1 - Lr.x1) * (L.x1 - Lr.x1) + (L.y1 - Lr.y1) * (L.y1 - Lr.y1));
                        ldb = sqrtf((L.x2 - Lr.x2) * (L.x2 - Lr.x2) + (L.y2 - Lr.y2) * (L.y2 - Lr.y2));

                        rdf = (float) jednostkiOb(st_node[st_element[i].node1].radius);
                        rdb = (float) jednostkiOb(st_node[st_element[i].node2].radius);

