                                if (Txx_>TxGrM[1]) TxGrM[1] = Txx_;
                                if (Txx_<TxGrm[1]) TxGrm[1] = Txx_;

                                Vy_ /= unit_factors->F_f;
                                Vz_ /= unit_factors->F_f;
                                Txx_ /= unit_factors->M_f;

