                                Sp_[1] = (NxM / Ax - fabs(MyM) / Wz + fabs(MzM) / Wy) / unit_factors->S_f;
                                Sp_[2] = (NxM / Ax + fabs(MyM) / Wz - fabs(MzM) / Wy) / unit_factors->S_f;
